@using Tempo.Blazor.Components.DataDisplay
@using Tempo.Blazor.Interfaces
@using Tempo.Blazor.Models

<TmMultiViewList TItem="TicketDto"
                 DataProvider="@_dataProvider"
                 ViewContext="tickets"
                 ViewProvider="@_viewProvider"
                 ViewFilterDefinitions="@_filterDefs"
                 ExternalFilterDefinitions="@_filterDefs"
                 ShowExternalFilterBuilder="true"
                 DisplayResolver="ResolveDisplay"
                 ViewCanCreateTenantViews="true"
                 CurrentUserId="@_userId"
                 CurrentTenantId="@_tenantId"
                 TitleField="t => t.Title"
                 SubTitleField="t => t.AssigneeName"
                 StatusLabelField="t => t.Status"
                 StatusColorField="t => GetStatusColor(t.Status)"
                 DateField="t => t.CreatedAt"
                 IdField="t => t.Id"
                 ShowSearch="true"
                 ShowViewSwitcher="true"
                 ViewMode="ListViewMode.Table"
                 DefaultPageSize="25"
                 OnItemClick="HandleTicketClick">
    <CardTemplate Context="ticket">
        <div class="ticket-card">
            <h3>@ticket.Title</h3>
            <span class="badge" style="background: @GetStatusColor(ticket.Status)">@ticket.Status</span>
            <p>@ticket.AssigneeName — @ticket.Priority</p>
        </div>
    </CardTemplate>
</TmMultiViewList>

@code {
    [Inject] private IDataTableDataProvider<TicketDto> DataProvider { get; set; } = default!;
    [Inject] private IDataTableViewProvider ViewProvider { get; set; } = default!;

    private IDataTableDataProvider<TicketDto> _dataProvider = default!;
    private IDataTableViewProvider _viewProvider = default!;
    private string _userId = "user-123";
    private string _tenantId = "tenant-abc";

    private List<FilterDefinition> _filterDefs =
    [
        new() { FieldName = "Title", FieldLabel = "Title", FieldType = FilterFieldType.Text },
        new() { FieldName = "Status", FieldLabel = "Status", FieldType = FilterFieldType.Select,
            Options = [
                new SelectOption<string>("Open", "Open"),
                new SelectOption<string>("InProgress", "In Progress"),
                new SelectOption<string>("Resolved", "Resolved"),
                new SelectOption<string>("Closed", "Closed")
            ] },
        new() { FieldName = "Priority", FieldLabel = "Priority", FieldType = FilterFieldType.Select,
            Options = [
                new SelectOption<string>("Low", "Low"),
                new SelectOption<string>("Medium", "Medium"),
                new SelectOption<string>("High", "High"),
                new SelectOption<string>("Critical", "Critical")
            ] },
        new() { FieldName = "CreatedAt", FieldLabel = "Created", FieldType = FilterFieldType.Date }
    ];

    protected override void OnInitialized()
    {
        _dataProvider = DataProvider;
        _viewProvider = ViewProvider;
    }

    /// <summary>
    /// DisplayResolver: localizes field labels and enum filter values.
    /// Set once on TmMultiViewList — flows to ViewManager, FilterBuilder, and filter chips.
    /// </summary>
    private string? ResolveDisplay(string fieldName, string? rawValue)
    {
        if (rawValue is null)
        {
            return fieldName switch
            {
                "Title" => "Ticket Title",
                "Status" => "Status",
                "Priority" => "Priority",
                "CreatedAt" => "Created Date",
                _ => null
            };
        }
        return (fieldName, rawValue) switch
        {
            ("Status", "Open") => "Open",
            ("Status", "InProgress") => "In Progress",
            ("Status", "Resolved") => "Resolved",
            ("Status", "Closed") => "Closed",
            ("Priority", "Low") => "Low",
            ("Priority", "Medium") => "Medium",
            ("Priority", "High") => "High",
            ("Priority", "Critical") => "Critical",
            _ => null
        };
    }

    private static string GetStatusColor(string? status) => status switch
    {
        "Open" => "#3b82f6",
        "InProgress" => "#f59e0b",
        "Resolved" => "#22c55e",
        "Closed" => "#6b7280",
        _ => "#94a3b8"
    };

    private void HandleTicketClick(TicketDto ticket) { /* navigate to detail */ }
}

using Tempo.Blazor.Interfaces;
using Tempo.Blazor.Models;
using System.Net.Http.Json;

/// <summary>
/// Server-side data provider — implements IDataTableDataProvider to load data
/// from an API. Works with both TmDataTable and TmMultiViewList.
/// GetGroupedDataAsync uses the default (returns null → client-side grouping fallback).
/// Override GetGroupedDataAsync for server-side grouping support.
/// </summary>
public class TicketHttpDataProvider : IDataTableDataProvider<TicketDto>
{
    private readonly HttpClient _http;

    public TicketHttpDataProvider(HttpClient http) => _http = http;

    public async Task<PagedResult<TicketDto>> GetDataAsync(DataTableQuery query, CancellationToken ct = default)
    {
        var qs = $"?page={query.Page}&pageSize={query.PageSize}";
        if (!string.IsNullOrEmpty(query.SearchText))
            qs += $"&search={Uri.EscapeDataString(query.SearchText)}";
        if (!string.IsNullOrEmpty(query.SortColumn))
            qs += $"&sortBy={Uri.EscapeDataString(query.SortColumn)}&sortDesc={query.SortDescending}";
        foreach (var f in query.Filters)
            qs += $"&filterColumn={Uri.EscapeDataString(f.Column)}&filterOperator={Uri.EscapeDataString(f.Operator)}&filterValue={Uri.EscapeDataString(f.Value?.ToString() ?? "")}";

        return await _http.GetFromJsonAsync<PagedResult<TicketDto>>($"/api/tickets{qs}", ct) ?? new();
    }
}

