@using Tempo.Blazor.Components.DataDisplay
@using Tempo.Blazor.Models

@* Server-side grouping: When GroupableFields are set and DataProvider implements
   GetGroupedDataAsync, the component calls GetGroupedDataAsync with GroupByColumns
   and GroupPageRequests in the DataTableQuery. If GetGroupedDataAsync returns null,
   it falls back to client-side grouping.

   Per-group pagination: When the server returns GroupPaging metadata,
   TmMultiViewList renders a compact TmPagination inside each expanded group
   (works in all 3 view modes). The global footer pagination is hidden
   when grouping is active. *@

<TmMultiViewList TItem="PersonDto"
                 DataProvider="@_dataProvider"
                 ViewContext="persons-list"
                 TitleField="@(p => p.FullName)"
                 SubTitleField="@(p => p.Email)"
                 StatusLabelField="@(p => p.IsActive ? "Active" : "Inactive")"
                 StatusColorField="@(p => p.IsActive ? "#22c55e" : "#ef4444")"
                 GroupableFields="@_groupFields"
                 ShowSearch="true"
                 ShowViewSwitcher="true"
                 DefaultPageSize="10" />

@code {
    [Inject] private IDataTableDataProvider<PersonDto> DataProvider { get; set; } = default!;
    private IDataTableDataProvider<PersonDto> _dataProvider = default!;

    // Define which fields the user can group by
    private readonly IReadOnlyList<GroupFieldDefinition<PersonDto>> _groupFields =
    [
        new GroupFieldDefinition<PersonDto>
        {
            FieldName = "Role",
            Label = "Role",
            FieldAccessor = p => p.Role
        },
        new GroupFieldDefinition<PersonDto>
        {
            FieldName = "Department",
            Label = "Department",
            FieldAccessor = p => p.Department
        },
        new GroupFieldDefinition<PersonDto>
        {
            FieldName = "IsActive",
            Label = "Active",
            FieldAccessor = p => p.IsActive,
            DisplayFormatter = v => v is true ? "Active" : "Inactive"
        }
    ];

    protected override void OnInitialized() => _dataProvider = DataProvider;
}

